// pubspec.yaml:
//   dependencies:
//     mobx: ^2.3.0
//     flutter_mobx: ^2.2.0
//   dev_dependencies:
//     build_runner: ^2.4.0
//     mobx_codegen: ^2.6.0

// FILE: counter_store.dart
import 'package:mobx/mobx.dart';
part 'counter_store.g.dart';

class CounterStore = _CounterStore with _$CounterStore;

abstract class _CounterStore with Store {
  @observable
  int count = 0;

  @computed
  int get doubled => count * 2;

  @action
  void increment() => count++;

  @action
  void reset() => count = 0;
}

// Run:  dart run build_runner build --delete-conflicting-outputs
// This generates counter_store.g.dart with the reactive machinery.

// FILE: main.dart
import 'package:flutter/material.dart';
import 'package:flutter_mobx/flutter_mobx.dart';
import 'counter_store.dart';

final store = CounterStore();

void main() => runApp(const MaterialApp(home: HomePage()));

class HomePage extends StatelessWidget {
  const HomePage({super.key});

  @override
  Widget build(BuildContext context) => Scaffold(
    appBar: AppBar(title: const Text('MobX counter')),
    body: Center(
      // Observer rebuilds when ANY observable it reads changes.
      child: Observer(builder: (_) => Column(
        mainAxisAlignment: MainAxisAlignment.center,
        children: [
          Text('count: ${store.count}', style: const TextStyle(fontSize: 30)),
          Text('doubled: ${store.doubled}', style: const TextStyle(fontSize: 20)),
        ],
      )),
    ),
    floatingActionButton: FloatingActionButton(
      onPressed: store.increment,
      child: const Icon(Icons.add),
    ),
  );
}

// Beyond Observer widgets, MobX has three programmatic reactions:

// (1) autorun — runs immediately, then whenever any observable it reads changes
autorun((_) => print('count is now ${store.count}'));

// (2) reaction — declaratively watch a projection
reaction<int>(
  (_) => store.count,               // observed
  (val) => print('count changed to $val'),  // callback
);

// (3) when — one-shot: fire the callback the first time predicate is true
when((_) => store.count > 10, () => print('reached 10!'));

// All three return a Dispose function you should call to prevent leaks:
final dispose = autorun((_) => print(store.count));
// ... later:
dispose();

